              "ALT_Polkit:Permission to run a program as another user": {
                "displayName": "Permission to run a program as another user",
                "header": {
                  "class": "User",
                  "name": "org.freedesktop.policykit.exec-user",
                  "displayName": "Permission to run a program as another user",
                  "explainText": "The policy controls the restriction on the ability to run the program as another user\n\nAuthentication is required to run a program as another user.\n\nDisabled/Unconfigured — restrictions are defined by system parameters.\n\nEnabled — restriction with defined rights;\n\nPossible values:\n\n\"No\" — set restriction with action denial (user is not allowed to perform the action);\n\n\"Yes\" — remove the restriction (the user can perform the action without any authentication);\n\n\"Auth_self\" — the user must enter his/her password for authentication. Note, this level of restriction is not sufficient for most multi-user applications, \"Auth_admin\" is usually recommended;\n\n\"Auth_admin\" — the user must enter the administrator password at each request. Requires authentication of the user with administrator privileges;\n\n\"Auth_self_keep\" — similar to \"Auth_self\", but authorization is maintained for a short period of time (e.g., five minutes). Note, this level of restriction is insufficient for most multi-user applications, \"Auth_admin_keep\" is generally recommended;\n\n\"Auth_admin_keep\" — similar to \"Auth_admin\", but authorization is maintained for a short period of time (e.g., five minutes);\n\nNote: the possession of administrative rights in a PolicyKit context is determined by its rules. By default, Alt asks for the password of a user in the \"wheel\" group.",
                  "key": "Software\\BaseALT\\Policies\\Polkit",
                  "valueName": "org.freedesktop.policykit.exec",
                  "presentation": "$(presentation.org-freedesktop-Policykit-user-pr)",
                  "parentCategory": "system:ALT_Polkit",
                  "supportedOn": "At least ALT Platform 10"
                },
                "Software\\BaseALT\\Policies\\Polkit\\org.freedesktop.policykit.exec": {
                  "metadata": {
                    "type": "enum",
                    "id": "OrgFreedesktopPolicykit_setter",
                    "valueName": "org.freedesktop.policykit.exec",
                    "required": true,
                    "items": {
                      "No": "No",
                      "Yes": "Yes",
                      "Auth_self": "Auth_self",
                      "Auth_admin": "Auth_admin",
                      "Auth_self_keep": "Auth_self_keep",
                      "Auth_admin_keep": "Auth_admin_keep"
                    },
                    "label": "Варианты ограничений:",
                    "defaultItem": "1"
                  },
                  "data": "Read_Path_GPT('Software\\BaseALT\\Policies\\Polkit\\org.freedesktop.policykit.exec')"
                }
              }
